class Solution {
public:
    int maxProfit(vector<int>& prices) {
        if (prices.size() <= 1){
            return 0;
        }

        int minp = prices[0];
        int profit = 0;

        for (int val : prices){
            if (val < minp){
                minp = val;
            }
            else if (val > minp){
                profit += val - minp;
                minp = val;
            }

        }


        return profit;
    }
};
